int main()
{
	std::vector v{ 1, 2, 3, 4, 5, 6, 7 };

	auto it{ v.begin() };

	++it; // move to second element
	std::cout << *it << '\n';

	it = v.erase(it); // erase the element currently being iterated over, set `it` to next element

	std::cout << *it << '\n'; // now ok, prints 3

	return 0;
}Next lesson18.3Introduction to standard library algorithmsBack to table of contentsPrevious lesson18.1Sorting an array using selection sort(h/t to nascardriver for significant contributions to this lesson)

